SELECT COUNT(DISTINCT household_id) AS distinct_households, SUM(total) AS total_movements
FROM movements
WHERE exit_destination_id = 1;

SELECT total
FROM movements
WHERE movement_id = 1;

SELECT destination_name
FROM exit_destinations
WHERE exit_destination_id = 1;

SELECT destination_name
FROM exit_destinations
WHERE city = 'Anytown';

SELECT COUNT(*) AS total_movements
FROM movements
WHERE population_type = 'all_persons' AND category_id = 1;
